import React from 'react';
import './CommandeList.css'; // optionnel

const CommandeList = ({ commandes = [], onSelect }) => {
  if (!Array.isArray(commandes)) {
    return <p>Aucune commande à afficher.</p>;
  }
  console.log(commandes);
  return (
    <div>
      <h2>Liste des Commandes</h2>
      <table className="commande-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Client</th>
            <th>Article</th>
            <th>Quantité</th>
            <th>Date</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {commandes.map((commande) => (
            <tr key={commande.idCOM}>
              <td>{commande.idCOM}</td>
              <td>{commande.nomCli}</td>
              <td>{commande.libelle}</td>
              <td>{commande.qte}</td>
              <td>{commande.dateCom}</td>
              <td>
              <button onClick={() => onSelect(commande)}>
                  Modifier / Supprimer
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default CommandeList;
